#include <stdio.h>
#include <stdlib.h>
#include <math.h>

static void factorize(long long n, long long *primes, int *cnt) {
    *cnt = 0;
    for (long long p = 2; p * p <= n; ++p) {
        if (n % p == 0) {
            primes[(*cnt)++] = p;
            while (n % p == 0) n /= p;
        }
    }
    if (n > 1) primes[(*cnt)++] = n;
}

static long long countDivisible(long long L, long long R, long long d) {
    if (d == 0) return 0;
    // works for negative L,R because C truncates toward zero; the formula is still correct for counting multiples.
    return R / d - (L - 1) / d;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long Y, X1, X2; scanf("%lld %lld %lld", &Y, &X1, &X2);
        long long y = llabs(Y);
        long long total = X2 - X1 + 1;
        if (y == 1) { printf("%lld\n", total); continue; }
        long long primes[12]; int pcnt; factorize(y, primes, &pcnt);
        long long bad = 0;
        int subsets = 1 << pcnt;
        for (int mask = 1; mask < subsets; ++mask) {
            long long mult = 1;
            int bits = 0;
            for (int i = 0; i < pcnt; ++i) if (mask & (1 << i)) {
                mult *= primes[i];
                ++bits;
            }
            long long cnt = countDivisible(X1, X2, mult);
            if (bits & 1) bad += cnt; else bad -= cnt;
        }
        printf("%lld\n", total - bad);
    }
    return 0;
}

