import java.io.*;
import java.util.*;

public class Main {
    private static List<Long> factorize(long n) {
        List<Long> primes = new ArrayList<>();
        for (long p = 2; p * p <= n; ++p) {
            if (n % p == 0) {
                primes.add(p);
                while (n % p == 0) n /= p;
            }
        }
        if (n > 1) primes.add(n);
        return primes;
    }
    private static long countDivisible(long L, long R, long d) {
        return R / d - (L - 1) / d;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long Y = Long.parseLong(st.nextToken());
            long X1 = Long.parseLong(st.nextToken());
            long X2 = Long.parseLong(st.nextToken());
            long y = Math.abs(Y);
            long total = X2 - X1 + 1;
            if (y == 1) {
                sb.append(total).append('\n');
                continue;
            }
            List<Long> primes = factorize(y);
            int k = primes.size();
            long bad = 0;
            for (int mask = 1; mask < (1 << k); ++mask) {
                long mult = 1; int bits = 0;
                for (int i = 0; i < k; ++i) if ((mask & (1 << i)) != 0) {
                    mult *= primes.get(i);
                    bits++;
                }
                long cnt = countDivisible(X1, X2, mult);
                if ((bits & 1) == 1) bad += cnt; else bad -= cnt;
            }
            sb.append(total - bad).append('\n');
        }
        System.out.print(sb.toString());
    }
}

