#!/usr/bin/env python3
import sys, math

def factorize(n):
    primes = []
    p = 2
    while p * p <= n:
        if n % p == 0:
            primes.append(p)
            while n % p == 0:
                n //= p
        p += 1 if p == 2 else 2
    if n > 1:
        primes.append(n)
    return primes

def count_divisible(L, R, d):
    return R // d - (L - 1) // d

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        Y = int(next(it)); X1 = int(next(it)); X2 = int(next(it))
        y = abs(Y)
        total = X2 - X1 + 1
        if y == 1:
            out.append(str(total))
            continue
        primes = factorize(y)
        k = len(primes)
        bad = 0
        for mask in range(1, 1 << k):
            mult = 1
            bits = 0
            for i in range(k):
                if mask & (1 << i):
                    mult *= primes[i]
                    bits += 1
            cnt = count_divisible(X1, X2, mult)
            if bits & 1:
                bad += cnt
            else:
                bad -= cnt
        out.append(str(total - bad))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

